/* Good match when assembly repeatedly accesses:
   [ptr+0], [ptr+4], [ptr+6], [ptr+8] */

#include <stdint.h>
#include <stddef.h>

int check_key(const uint8_t *buf, size_t len) {
    uint32_t acc = 0x1337;
    if (len != 8) return 0;
    for (size_t i = 0; i < len; i++) {
        acc = ((acc << 5) + acc) ^ buf[i];
    }
    return acc == 0x52A4F91C;
}

