#include <stddef.h>

/* Decompiled shape:
   acc = 0;
   for (i = 0; i < len; i++) {
       acc = acc + ((uint8_t)buf[i] ^ 0x20);
   }
   return acc == 300;
*/

int check(const unsigned char *buf, size_t len) {
    unsigned int acc = 0;
    for (size_t i = 0; i < len; i++) {
        acc += (buf[i] ^ 0x20);
    }
    return acc == 300;
}

#include <stdint.h>
#include <stddef.h>
#include <string.h>

typedef struct Header {
    uint32_t magic;
    uint16_t type;
    uint16_t size;
} Header;

int parse_header(const unsigned char *buf, size_t len, Header *out) {
    if (len < sizeof(Header)) return 0;
    memcpy(out, buf, sizeof(Header));
    return 1;
}

#include <stdint.h>
#include <stddef.h>
#include <string.h>

int check_serial(const char *s) {
    uint32_t acc = 0;
    size_t len = strlen(s);
    if (len != 6) return 0;
    for (size_t i = 0; i < len; i++) {
        acc += ((unsigned char)s[i] ^ 0x5A) + (uint32_t)i;
    }
    return acc == 512;
}

